const body = $input.item.json.body || $input.item.json;
const email = (body.email || '').toString().trim().toLowerCase();
const type = (body.type || '').toString().toLowerCase();
const details = (body.details || '').toString().slice(0, 4000);
const origin = (body.origin || $input.item.json.headers?.referer || '').toString();
// Basic email shape — not RFC-perfect but rejects junk.
if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) {
  return [{ json: { _error: 'invalid-email' } }];
}
const validTypes = ['access', 'erasure', 'portability', 'rectification', 'restriction', 'objection', 'other'];
if (!validTypes.includes(type)) {
  return [{ json: { _error: `invalid-type — must be one of: ${validTypes.join(', ')}` } }];
}
const id = (typeof crypto !== 'undefined' && crypto.randomUUID) ? crypto.randomUUID() : `${Date.now().toString(36)}-${Math.random().toString(36).slice(2,10)}`;
// SLA: GDPR Art. 12(3) — 1 month default, extendable to 3 months for complex requests.
const dueAt = new Date(Date.now() + 30 * 864e5).toISOString();
return [{ json: { id, email, type, details, origin, ts: new Date().toISOString(), dueAt, status: 'open' } }];

const v = $('Validate request').first().json;
const due = new Date(v.dueAt).toLocaleDateString();
return [{ json: {
  priority: 'P1',
  source: 'gdpr-intake',
  message: `New GDPR request · type: ${v.type} · email: ${v.email} · due by: ${due}\n\nDetails: ${v.details || '(none provided)'}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/maintain/compliance'
} }];
